import os
import numpy as np
import cv2
from flask import Flask, request, jsonify
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from sklearn.metrics.pairwise import cosine_similarity
import pickle
import face_recognition
from flask_cors import CORS
import hashlib
import time

app = Flask(__name__)
CORS(app)

# Security parameters
NOISE_LEVEL = 0.01
MODEL_PATH = "face_model.pkl"
ENCODINGS_PATH = "face_encodings.npy"
LABELS_PATH = "face_labels.npy"

class FacialRecognitionAPI:
    def __init__(self):
        self.model = None
        self.label_encoder = None
        self.encodings = None
        self.labels = None
        self.known_faces = {}
        
    def _add_noise(self, features):
        """Add noise to prevent model inversion"""
        noise = np.random.normal(0, NOISE_LEVEL, features.shape)
        return features + noise
    
    def _hash_features(self, features):
        """Hash features to prevent direct access"""
        return hashlib.sha256(features.tobytes()).hexdigest()
    
    def train_model(self, image_paths, labels):
        """Train the facial recognition model"""
        encodings = []
        processed_labels = []
        
        for img_path, label in zip(image_paths, labels):
            image = face_recognition.load_image_file(img_path)
            face_locations = face_recognition.face_locations(image)
            
            if len(face_locations) == 0:
                continue
                
            face_encodings = face_recognition.face_encodings(image, face_locations)
            
            if len(face_encodings) > 0:
                # Add noise to prevent inversion
                noisy_encoding = self._add_noise(face_encodings[0])
                encodings.append(noisy_encoding)
                processed_labels.append(label)
        
        if len(encodings) == 0:
            raise ValueError("No faces found in training images")
            
        self.encodings = np.array(encodings)
        self.labels = np.array(processed_labels)
        
        # Encode labels
        self.label_encoder = LabelEncoder()
        encoded_labels = self.label_encoder.fit_transform(self.labels)
        
        # Train SVM model
        self.model = SVC(kernel='linear', probability=True, C=1.0)
        self.model.fit(self.encodings, encoded_labels)
        
        # Save model
        self._save_model()
        
    def _save_model(self):
        """Save model to disk"""
        model_data = {
            'model': self.model,
            'label_encoder': self.label_encoder,
            'encodings': self.encodings,
            'labels': self.labels
        }
        
        with open(MODEL_PATH, 'wb') as f:
            pickle.dump(model_data, f)
            
    def _load_model(self):
        """Load model from disk"""
        if os.path.exists(MODEL_PATH):
            with open(MODEL_PATH, 'rb') as f:
                model_data = pickle.load(f)
                
            self.model = model_data['model']
            self.label_encoder = model_data['label_encoder']
            self.encodings = model_data['encodings']
            self.labels = model_data['labels']
            return True
        return False
    
    def recognize_face(self, image_path):
        """Recognize faces in image and return probability distribution"""
        if self.model is None:
            if not self._load_model():
                raise ValueError("Model not trained or loaded")
                
        # Load image
        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image)
        face_encodings = face_recognition.face_encodings(image, face_locations)
        
        results = []
        
        for face_encoding in face_encodings:
            # Add noise for security
            noisy_encoding = self._add_noise(face_encoding)
            
            # Get prediction probabilities
            probabilities = self.model.predict_proba([noisy_encoding])[0]
            predicted_class = self.model.predict([noisy_encoding])[0]
            
            # Get class names
            class_names = self.label_encoder.classes_
            
            # Create probability distribution
            prob_dist = {}
            for i, (class_name, prob) in enumerate(zip(class_names, probabilities)):
                prob_dist[class_name] = float(prob)
                
            results.append({
                'face_locations': face_locations[0],
                'probabilities': prob_dist,
                'confidence': float(np.max(probabilities))
            })
            
        return results

# Initialize API
face_api = FacialRecognitionAPI()

@app.route('/train', methods=['POST'])
def train():
    """Train the model with employee photos"""
    try:
        data = request.get_json()
        image_paths = data.get('image_paths', [])
        labels = data.get('labels', [])
        
        if len(image_paths) != len(labels):
            return jsonify({'error': 'Mismatch between image paths and labels'}), 400
            
        face_api.train_model(image_paths, labels)
        
        return jsonify({'status': 'success', 'message': 'Model trained successfully'})
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/recognize', methods=['POST'])
def recognize():
    """Recognize faces in uploaded image"""
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
            
        file = request.files['image']
        if file.filename == '':
            return jsonify({'error': 'No image selected'}), 400
            
        # Save temporary image
        temp_path = f"temp_{int(time.time())}.jpg"
        file.save(temp_path)
        
        # Recognize faces
        results = face_api.recognize_face(temp_path)
        
        # Clean up
        os.remove(temp_path)
        
        return jsonify({'results': results})
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/status', methods=['GET'])
def status():
    """Check if model is trained"""
    try:
        if face_api.model is not None:
            return jsonify({'status': 'trained', 'model_exists': True})
        elif os.path.exists(MODEL_PATH):
            return jsonify({'status': 'trained', 'model_exists': True})
        else:
            return jsonify({'status': 'not_trained', 'model_exists': False})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

